import{_ as d,X as s,Y as h,$ as t,a0 as e,a1 as a,a2 as i,a3 as c,F as r}from"./framework-abbf9d44.js";const l={},p=c('<h1 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h1><h2 id="📘-基本信息" tabindex="-1"><a class="header-anchor" href="#📘-基本信息" aria-hidden="true">#</a> 📘 基本信息</h2><table><thead><tr><th><strong>📖 书名</strong></th><th>《长安的荔枝》</th></tr></thead><tbody><tr><td><strong>🕵️‍♂️ 作者</strong></td><td>马伯庸</td></tr><tr><td><strong>💥 出版时间</strong></td><td>2022-10-01</td></tr><tr><td><strong>⏰ 阅读时间</strong></td><td>2024-10-23</td></tr></tbody></table><h2 id="🔍-为什么选择这本书" tabindex="-1"><a class="header-anchor" href="#🔍-为什么选择这本书" aria-hidden="true">#</a> 🔍 为什么选择这本书？</h2><p>偶然间在抖音看到了视频的切片，视频内容主要是在说，大家都在关注杨贵妃吃荔枝，却没有人关注荔枝是怎么到长安的？于是写了这么一个基层一线的故事。</p><p>个人觉的这个切入挺好的，也符合现在职场的特性，非常想知道在这个故事背景下，一线的员工是如何打怪升级的。也希望能有所启发，给现实带来一点改变。</p><h2 id="📒-阅读思考" tabindex="-1"><a class="header-anchor" href="#📒-阅读思考" aria-hidden="true">#</a> 📒 阅读思考</h2><p>转 一段感悟：</p><ul><li><p>不管收到什么文件，都要仔细核对。这也是本书故事起因，因李善德收到了荔枝领，没有仔细核对（荔枝煎和荔枝鲜），导致事后想去讨要说法，却没人搭理。</p></li><li><p>“和光同尘，雨露均沾，花花轿子众人齐”。这也让我想起家中长辈告诉的一句话“发表文章，要将领导名字放前面，自己的名字放最后；取得成绩，先感谢领导提携，其次感谢同事帮助”。李德善去岭南当地遇到各种阻拦，最后终于明白，要想办成一件事，需要带上每个部门才行，让大家都能从中获益，才最终才能将事情办成办好。</p></li><li><p>学会借势，不要一味依靠自身力量。李善德没有得到杨国忠帮助时，被人当个皮球踢来踢去，办不成事还积了一肚子的气，但有了杨国忠的“银牌”，官员立马转了态度。我们平时办事也一定要先和领导请示，再去办的时候就说领导交代的，大家不要相互为难。</p></li><li><p>自己的想法，不要轻易告诉别人。“就算你和他交际，好歹留上一手啊！如今倒好，他拿了荔枝转运法，为何不照葫芦画瓢，自去岭南取了新鲜荔枝回来？这份功劳，跟你半点关系也没有了！”李善德因为把自己的荔枝转运法告诉了别人，导致差点被抢了功劳。我们在职场也是一样，少说话多做事，特别是和利益相关的，绝对闭口不谈，别人问起就转移话题。</p></li><li><p>不要轻易给别人承诺。李善德答应富商将荔枝转运的差事交给他们商队，回京城后发现这事自己说了不算，最后失去了朋友，也失去了保存荔枝的容器，差点误了运送荔枝。</p></li><li><p>规则都是为弱者设立的。“流程，是弱者才要遵循的规矩”。李善德他按照规矩办事，处处碰壁，而靠着“银牌”却畅行无阻。</p></li></ul><hr><p>故事的结局是李善德揭露了官场的黑暗，并且选择了另外的一条路，一条遵循自己内心的路，一条干干净净的路，一条重回初心的路。这看起来狠热血，很出气，让人忍不住的高呼“卧槽“，但小说之外的我们呢？要不要这样做？李的结局给我了启示，流放岭南，看管荔枝园，就这样到了结局。但是，如果能坚定自己内心，先成为他，再消灭他呢？是不是不只是救自己，也能救他人，救苍生？</p>',11),_={id:"⛳-其他资料",tabindex:"-1"},u=t("a",{class:"header-anchor",href:"#⛳-其他资料","aria-hidden":"true"},"#",-1),f={href:"https://book.douban.com/subject/36104107/",target:"_blank",rel:"noopener noreferrer"};function b(x,m){const n=r("font"),o=r("ExternalLinkIcon");return s(),h("div",null,[p,t("h2",_,[u,e(" ⛳ "),a(n,{style:{color:"#52C41A"}},{default:i(()=>[e("其他资料")]),_:1})]),t("p",null,[t("a",f,[e("https://book.douban.com/subject/36104107/"),a(o)])])])}const k=d(l,[["render",b],["__file","index.html.vue"]]);export{k as default};
